const ALLOWED_HOSTS = [
  'localhost',
  '127.0.0.1',
  'yourdomain.com',
  'www.yourdomain.com',
  'app.yourdomain.com'
];

const ALLOWED_PROTOCOLS = ['https:'];
// Allow http only for localhost development
const LOCALHOST_ALLOWED_PROTOCOLS = ['http:', 'https:'];

const DEFAULT_REDIRECT = '/dashboard';

/**
 * Validates that a return URL is safe to redirect to (not an open redirect).
 * Only allows redirects to whitelisted hosts or relative paths on the same origin.
 */
function isValidReturnUrl(returnUrl) {
  if (!returnUrl || typeof returnUrl !== 'string') {
    return false;
  }

  // Trim whitespace
  const trimmed = returnUrl.trim();

  // Block empty strings
  if (trimmed.length === 0) {
    return false;
  }

  // Block protocol-relative URLs (e.g., //evil.com)
  if (trimmed.startsWith('//')) {
    return false;
  }

  // Block javascript:, data:, vbscript:, and other dangerous schemes
  const lowerTrimmed = trimmed.toLowerCase().replace(/\s/g, '');
  if (lowerTrimmed.startsWith('javascript:') ||
      lowerTrimmed.startsWith('data:') ||
      lowerTrimmed.startsWith('vbscript:') ||
      lowerTrimmed.startsWith('mailto:')) {
    return false;
  }

  // Allow relative paths that start with a single /
  if (trimmed.startsWith('/') && !trimmed.startsWith('//')) {
    // Additional check: ensure no backslash tricks (e.g., /\evil.com)
    if (trimmed.includes('\\')) {
      return false;
    }
    return true;
  }

  // For absolute URLs, validate against allowed hosts
  try {
    const parsed = new URL(trimmed);

    // Check if the host is in our allowlist
    if (!ALLOWED_HOSTS.includes(parsed.hostname)) {
      return false;
    }

    // Check protocol
    const isLocalhost = parsed.hostname === 'localhost' || parsed.hostname === '127.0.0.1';
    const allowedProtocols = isLocalhost ? LOCALHOST_ALLOWED_PROTOCOLS : ALLOWED_PROTOCOLS;

    if (!allowedProtocols.includes(parsed.protocol)) {
      return false;
    }

    return true;
  } catch (e) {
    // If URL parsing fails, reject it
    return false;
  }
}

/**
 * Sanitizes a valid return URL to ensure it's safe.
 * Should only be called after isValidReturnUrl returns true.
 */
function sanitizeReturnUrl(returnUrl) {
  const trimmed = returnUrl.trim();

  // For relative paths, return as-is (already validated)
  if (trimmed.startsWith('/') && !trimmed.startsWith('//')) {
    return trimmed;
  }

  // For absolute URLs, reconstruct to avoid any encoding tricks
  try {
    const parsed = new URL(trimmed);
    return parsed.toString();
  } catch (e) {
    return DEFAULT_REDIRECT;
  }
}

